const rows = $input.all().map(i => i.json);

const projetos = {};
for (const row of rows) {
  const pid = row.projeto_id;
  if (!projetos[pid]) {
    projetos[pid] = {
      id: pid,
      nome: row.projeto,
      responsavel: row.responsavel_projeto,
      status: row.status_projeto,
      prazo: row.prazo ? new Date(row.prazo).toLocaleDateString('pt-BR') : 'sem prazo',
      tarefas: []
    };
  }
  if (row.tarefa_id) {
    projetos[pid].tarefas.push({
      id: row.tarefa_id,
      titulo: row.tarefa,
      responsavel: row.responsavel_tarefa,
      status: row.status_tarefa
    });
  }
}

const lista = Object.values(projetos);
const hoje = new Date().toLocaleDateString('pt-BR');

const contexto = lista.map(p => {
  const tarefas = p.tarefas.length
    ? p.tarefas.map(t => `    - [${t.status}] ${t.titulo} (${t.responsavel})`).join('\n')
    : '    (sem tarefas)';
  return `Projeto: ${p.nome}\nStatus: ${p.status}\nResponsável: ${p.responsavel}\nPrazo: ${p.prazo}\nTarefas:\n${tarefas}`;
}).join('\n\n');

const prompt = `Você é um assistente de gestão de projetos de software. Hoje é ${hoje}.\n\nAnalise o estado atual dos projetos abaixo e identifique ações concretas que os desenvolvedores devem tomar agora.\n\n${contexto}\n\nRetorne APENAS JSON válido (sem markdown, sem texto adicional) neste formato exato:\n{\n  "analise_geral": "Resumo do estado em 2-3 frases diretas",\n  "alertas": ["alerta urgente 1", "alerta 2"],\n  "acoes": [\n    {"prioridade": "alta", "responsavel": "Nome", "projeto": "Nome", "acao": "O que fazer especificamente"}\n  ]\n}`;

return [{ json: {
  apiKey: process.env.ANTHROPIC_API_KEY,
  payload: {
    model: 'claude-sonnet-4-6',
    max_tokens: 1024,
    messages: [{ role: 'user', content: prompt }]
  }
} }];

const resp = $input.first().json;
const texto = resp.content?.[0]?.text ?? '{}';
let analise;
try {
  analise = JSON.parse(texto);
} catch {
  analise = { analise_geral: texto, alertas: [], acoes: [] };
}
analise.gerado_em = new Date().toISOString();
return [{ json: { analise } }];
